SELECT pa.application_id, pa.project_id, rp.project_name, pa.student_id, s.name AS student_name, s.student_number, s.major, s.grade, s.class AS clazz, pa.application_letter, pa.status, pa.apply_time, pa.review_time FROM project_applications pa LEFT JOIN research_projects rp ON pa.project_id = rp.project_id LEFT JOIN students s ON pa.student_id = s.user_id WHERE 1=1
AND pa.project_id = #{projectId}
AND pa.student_id = #{studentId}
AND rp.teacher_id = #{teacherId}
AND pa.status = #{status}
ORDER BY pa.apply_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM project_applications pa
LEFT JOIN research_projects rp ON pa.project_id = rp.project_id
WHERE 1=1

    AND pa.project_id = #{projectId}


    AND pa.student_id = #{studentId}


    AND rp.teacher_id = #{teacherId}


    AND pa.status = #{status}
